{
  "learner_outcomes": [
    {"label": "Bilingual Communicators", "rationale": "The plan embeds every schoolwide learner outcome in every lesson and pastoral session; Bilingual Communicators is one of the seven the desired_state names, and the school's purpose includes students communicating ideas in Chinese and English, so lessons that put this outcome to work carry it into daily teaching."},
    {"label": "Compassionate", "rationale": "The desired_state requires every lesson and Homeroom session to name and use one of the seven outcomes in a student task; Compassionate is among them, and the rationale ties the outcomes to the school's aim that students develop concern for the well-being of others."},
    {"label": "Confident", "rationale": "The plan puts each outcome to work in tasks where students try, check, and adjust; Confident is shown when self-assurance grows through taking risks and expressing ideas, which the action focus on student tasks directly exercises."},
    {"label": "Engaged", "rationale": "The desired_state moves the outcomes from a wall poster into the task a student does; Engaged is one of the seven, and the rationale names the vision that students be engaged and realize their academic potential."},
    {"label": "Innovative", "rationale": "Innovative is one of the seven outcomes the plan embeds in every lesson and pastoral session, so designing tasks that put it to work brings it into daily classroom practice across divisions."},
    {"label": "Reflective", "rationale": "The desired_state names a checked, recorded practice where students use a named outcome in a task; Reflective is one of the seven, exemplified in the draft by students regrading work against a Reflective prompt."},
    {"label": "Responsible", "rationale": "The plan opens pastoral sessions from a named outcome and closes with a student-chosen next step; Responsible is one of the seven and aligns with the school's aim that students cultivate an ethic of personal responsibility."}
  ],
  "stakeholder_impact": [
    {"label": "Students", "rationale": "The desired_state has students across IG1, IG2, AS, and A2 meet a named outcome inside the task they do and be able to name the outcome a lesson worked on, so students are the direct subjects of the embedding."},
    {"label": "Staff / Faculty", "rationale": "Teachers across the named departments and the Homeroom Teachers and Year Leaders in the SAO - Student Affairs Office change their lesson and session practice to name and use an outcome; the plan's adult-practice change rests on Staff / Faculty."},
    {"label": "Administration / Leadership", "rationale": "Curriculum and Teaching holds the standing termly record of how often lessons and pastoral sessions embed a named outcome; Administration / Leadership owns the observation and review that verifies the embedding held."}
  ],
  "areas_for_improvement": [
    {"label": "Faculty PD and PLC", "rationale": "The rationale names Faculty PD and PLC as a target; embedding the outcomes changes how teachers plan lessons and how Year Leaders run workshops and meetings, which is professional practice the plan develops and reviews each term."},
    {"label": "School Culture", "rationale": "The rationale names School Culture as a target; making the learner outcomes a working frame in both lessons and pastoral sessions across all year groups makes the shared outcomes part of how the school operates day to day."},
    {"label": "Curriculum and Learning", "rationale": "The desired_state requires every lesson to name one outcome and put it to work in a student task, and Curriculum and Teaching to keep a termly record; this changes lesson design and curriculum practice directly."}
  ],
